from __future__ import annotations
import json
from datetime import datetime, timezone
from pathlib import Path
from typing import Optional

class ConsentStore:
    """Append-only NDJSON consent log with an in-memory index for fast lookups."""

    def __init__(self, log_path: Path) -> None:
        self._path = log_path
        # subject_id → purpose → latest ConsentRecord
        self._index: dict[str, dict[str, ConsentRecord]] = {}
        self._load()

    def _load(self) -> None:
        if not self._path.exists():
            return
        for line in self._path.read_text().splitlines():
            if not line.strip():
                continue
            data = json.loads(line)
            record = ConsentRecord(**{
                **data,
                "purpose": ConsentPurpose(data["purpose"]),
                "mechanism": ConsentMechanism(data["mechanism"]),
                "captured_at": datetime.fromisoformat(data["captured_at"]),
                "expires_at": datetime.fromisoformat(data["expires_at"]) if data.get("expires_at") else None,
                "withdrawn_at": datetime.fromisoformat(data["withdrawn_at"]) if data.get("withdrawn_at") else None,
            })
            self._index.setdefault(record.subject_id, {})[record.purpose.value] = record

    def _append(self, record: ConsentRecord) -> None:
        import dataclasses
        row = {
            k: (v.value if isinstance(v, enum.Enum) else v.isoformat() if isinstance(v, datetime) else v)
            for k, v in dataclasses.asdict(record).items()
        }
        with self._path.open("a") as fh:
            fh.write(json.dumps(row) + "\n")

    def record_grant(self, record: ConsentRecord) -> None:
        self._append(record)
        self._index.setdefault(record.subject_id, {})[record.purpose.value] = record

    def record_withdrawal(
        self,
        subject_id: str,
        purpose: ConsentPurpose,
        reason: str = "",
    ) -> Optional[ConsentRecord]:
        existing = self._index.get(subject_id, {}).get(purpose.value)
        if existing is None:
            return None
        # New record — withdrawal is captured as a separate record
        withdrawal = ConsentRecord(
            record_id=existing.record_id,   # same record_id, updated state
            subject_id=subject_id,
            purpose=purpose,
            granted=False,
            mechanism=existing.mechanism,
            policy_version=existing.policy_version,
            app_id=existing.app_id,
            captured_at=existing.captured_at,
            ip_hash=existing.ip_hash,
            user_agent_hash=existing.user_agent_hash,
            expires_at=existing.expires_at,
            withdrawn_at=datetime.now(timezone.utc),
            withdrawal_reason=reason,
        )
        self._append(withdrawal)
        self._index[subject_id][purpose.value] = withdrawal
        return withdrawal

    def has_active_consent(self, subject_id: str, purpose: ConsentPurpose) -> bool:
        record = self._index.get(subject_id, {}).get(purpose.value)
        return record is not None and record.is_active()

    def list_consents(self, subject_id: str) -> dict[str, bool]:
        return {
            purpose: record.is_active()
            for purpose, record in self._index.get(subject_id, {}).items()
        }

from __future__ import annotations
from typing import Any

class ConsentAwareRetriever:
    """Wraps a base retriever and enforces RAG_RETRIEVAL consent."""

    def __init__(
        self,
        base_retriever,
        consent_service: ConsentService,
        *,
        raise_on_no_consent: bool = True,
    ) -> None:
        self._retriever = base_retriever
        self._consent = consent_service
        self._raise = raise_on_no_consent

    def retrieve(
        self,
        query: str,
        *,
        subject_id: str,
        top_k: int = 5,
    ) -> list[dict[str, Any]]:
        if not self._consent.check_consent(subject_id, ConsentPurpose.RAG_RETRIEVAL):
            if self._raise:
                raise PermissionError(
                    f"User {subject_id!r} has not consented to RAG retrieval. "
                    "Prompt the user to grant RAG_RETRIEVAL consent before proceeding."
                )
            return []

        return self._retriever.retrieve(query, top_k=top_k)

from __future__ import annotations

BREAKING_POLICY_VERSIONS: set[str] = {
    "2024-Q1",  # Added CROSS_APP_SHARING purpose
    "2023-Q3",  # Extended RAG_RETRIEVAL to include chat history
}

def requires_re_consent(record: ConsentRecord, current_version: str) -> bool:
    """True if the consent was given under a policy version that has since had
    a breaking change affecting the same purpose."""
    if record.policy_version == current_version:
        return False
    # Any breaking version released after the consent was given requires re-capture
    # In production, replace this with a version ordering check
    return record.policy_version in BREAKING_POLICY_VERSIONS

def list_subjects_needing_re_consent(
    store: ConsentStore,
    all_subject_ids: list[str],
) -> list[tuple[str, ConsentPurpose]]:
    """Return (subject_id, purpose) pairs where re-consent is needed."""
    result = []
    for sid in all_subject_ids:
        for purpose_str, record in store._index.get(sid, {}).items():
            if record.is_active() and requires_re_consent(record, CURRENT_POLICY_VERSION):
                result.append((sid, ConsentPurpose(purpose_str)))
    return result

from __future__ import annotations
from typing import Iterable

def filter_training_records(
    records: Iterable[dict],
    consent_service: ConsentService,
) -> list[dict]:
    """Remove interaction records from users who have not consented to fine-tune training."""
    approved = []
    for rec in records:
        subject_id = rec.get("user_id") or rec.get("subject_id")
        if not subject_id:
            continue   # skip records with no identity
        if consent_service.check_consent(subject_id, ConsentPurpose.FINE_TUNE_TRAINING):
            approved.append(rec)
    return approved

def emit_analytics_event(
    subject_id: str,
    event: dict,
    consent_service: ConsentService,
    analytics_sink,
) -> None:
    if consent_service.check_consent(subject_id, ConsentPurpose.USAGE_ANALYTICS):
        analytics_sink.emit({"subject_id": subject_id, **event})
    else:
        # Emit anonymised aggregate event with no user identifier
        analytics_sink.emit({"subject_id": None, "event_type": event.get("event_type")})
